import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Arrival {
  line: string;
  destination: string;
  arrivalTime: string;
  delay: string;
}

interface TransitData {
  station: string;
  nextArrivals: Arrival[];
}

export default function Widget() {
  const transitData = response.data as TransitData;
  const { station, nextArrivals } = transitData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#303030', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              {station}
            </Typography>
          </Box>

          <Stack spacing={1}>
            {nextArrivals.map((arrival, index) => (
              <Box key={index} sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Box>
                  <Typography variant="body1" fontWeight={500} sx={{ color: '#4CAF50' }}>
                    {arrival.line}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    To {arrival.destination}
                  </Typography>
                </Box>
                <Box textAlign="right">
                  <Typography variant="body2" fontWeight={500} sx={{ color: '#FF5722' }}>
                    {arrival.arrivalTime}
                  </Typography>
                  <Chip
                    label={arrival.delay}
                    sx={{
                      fontSize: '10px',
                      bgcolor: arrival.delay === 'On Time' ? '#4CAF50' : '#FF5722',
                      color: '#FFFFFF',
                      height: 20,
                    }}
                  />
                </Box>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
